import React, { useState, useEffect } from "react";
import "../assets/css/products.css"; 

export default function Footer() {
    const [products, setProducts] = useState([]);  // Stan do przechowywania produktów

    useEffect(() => {
        // Ładowanie pliku JSON po załadowaniu komponentu
        fetch("/conf/hero/config.json") // Zakładając, że plik JSON znajduje się w public/core/db
            .then(response => response.json())
            .then(data => {
                // Ustawianie produktów w stanie
                setProducts(data);
            })
            .catch(error => console.error("Błąd wczytywania danych:", error));
    }, []); // Tylko przy pierwszym renderowaniu

    return (
        <section className="products">
            <h2>Nasze Produkty</h2>
            <div className="product-container">
                {products.length > 0 ? (
                    products.map((product, index) => (
                        <div key={index} className="product-card">
                            <img src={product.img} alt={product.title} />
                            <h3>{product.title}</h3>
                            <p>{product.description}</p>
                            <button>Kup teraz</button>
                        </div>
                    ))
                ) : (
                    <p>Ładowanie produktów...</p>
                )}
            </div>
        </section>
    );
}
